      "path": "src/modules/projects/service.js",
      "content": "const { generateId } = require('../../lib/id');
const { BadRequestError, NotFoundError } = require('../../lib/errors');

let projects = [];

function createProject(req, res) {
  const { name } = req.body;
  if (!name) {
    throw new BadRequestError('Name is required');
  }
  const project = { id: generateId(), name, members: [], tasks: [] };
  projects.push(project);
  res.status(201).json({ project });
}

function getProjects(req, res) {
  res.json({ projects });
}

function getProjectMembers(req, res) {
  const { projectId } = req.params;
  const project = projects.find(p => p.id === projectId);
  if (!project) {
    throw new NotFoundError('Project not found');
  }
  res.json({ members: project.members });
}

function getProjectTasks(req, res) {
  const { projectId } = req.params;
  const project = projects.find(p => p.id === projectId);
  if (!project) {
    throw new NotFoundError('Project not found');
  }
  res.json({ tasks: project.tasks });
}

module.exports = { createProject, getProjects, getProjectMembers, getProjectTasks };
